	_, _, _, err := sr.Lookup(ctx, "some.nonexistent.invalid.example")
	elapsed := time.Since(start)

	if err == nil {
		t.Fatal("Lookup(canceled ctx): expected non-nil error, got nil")
	}
	if !errors.Is(err, context.Canceled) {
